import{_ as e,o as r,c as i,ag as t}from"./chunks/framework.f_9xDHrT.js";const f=JSON.parse('{"title":"钓特定鱼类","description":"如何用 MissFisher 钓特定鱼类。","frontmatter":{"title":"钓特定鱼类","description":"如何用 MissFisher 钓特定鱼类。"},"headers":[],"relativePath":"manual/scenarios/fish.md","filePath":"manual/scenarios/fish.md","lastUpdated":1778062636000}'),l={name:"manual/scenarios/fish.md"};function o(s,a,h,n,d,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="钓特定鱼类" tabindex="-1">钓特定鱼类 <a class="header-anchor" href="#钓特定鱼类" aria-label="Permalink to &quot;钓特定鱼类&quot;">​</a></h1><blockquote><p>钓场之王、海钓中的普通海域稀有鱼、宠物、部分捕鱼人的特殊交付需求。</p></blockquote><h2 id="通用方法" tabindex="-1">通用方法 <a class="header-anchor" href="#通用方法" aria-label="Permalink to &quot;通用方法&quot;">​</a></h2><p>通过预设启动。</p><h2 id="获取目标鱼类的信息" tabindex="-1">获取目标鱼类的信息 <a class="header-anchor" href="#获取目标鱼类的信息" aria-label="Permalink to &quot;获取目标鱼类的信息&quot;">​</a></h2><p>使用各种工具查看目标鱼的窗口期或可钓条件：</p><ul><li><a href="https://fish.ffmomola.com" target="_blank" rel="noreferrer">鱼糕</a></li><li><a href="https://ff14fish.carbuncleplushy.com" target="_blank" rel="noreferrer">Fish Tracker App</a></li><li>Dalamud 插件 <a href="https://github.com/AtmoOmen/GatherBuddyReborn" target="_blank" rel="noreferrer">GatherBuddy Reborn</a></li></ul><h2 id="搜索和启动" tabindex="-1">搜索和启动 <a class="header-anchor" href="#搜索和启动" aria-label="Permalink to &quot;搜索和启动&quot;">​</a></h2><p><strong>搜索：</strong></p><ol><li>在主界面 - 主页的搜索框搜索预设。（也可输入汉语拼音、逐字的首字母，或分词式搜索）</li><li>点击在搜索框下方的补全菜单中的预设。（边框的颜色也会提示是否有匹配的预设名）</li></ol><p><strong>查看、前往和启动：</strong></p><ol><li>点查看按钮，可在聊天窗口查看预设的备注、目标所需的传承录、获得力、钓饵。</li><li>点前往按钮，可发起前往目标所在地的自动传送和导航。</li><li>确认模式下拉显示的是预设模式。</li><li>靠近可钓区域，点启动按钮来启动。</li></ol><h2 id="有咬饵条件的一般鱼类" tabindex="-1">有咬饵条件的一般鱼类 <a class="header-anchor" href="#有咬饵条件的一般鱼类" aria-label="Permalink to &quot;有咬饵条件的一般鱼类&quot;">​</a></h2><p>可在窗口期开始前启动对应预设，MissFisher 会自动进行窗口期前的预备动作。</p><p>窗口期的开始、结束、以及钓上目标时，MissFisher 都会进行提醒。</p><h2 id="钓场之皇" tabindex="-1">钓场之皇 <a class="header-anchor" href="#钓场之皇" aria-label="Permalink to &quot;钓场之皇&quot;">​</a></h2><p>部分钓场之皇有着复杂的捕鱼人之识触发条件，由于有着各种意外情况，MissFisher 难以在这种情形下完成全自动的准备和钓鱼，所以请务必查看对应钓场之皇的预设说明，从各种工具或攻略主动了解并理解钓场之皇的钓法。</p><h2 id="鱼眼预设" tabindex="-1">鱼眼预设 <a class="header-anchor" href="#鱼眼预设" aria-label="Permalink to &quot;鱼眼预设&quot;">​</a></h2><p>鱼眼预设一般以鱼名开头，或以 <code>鱼眼</code> / <code>-Fish Eyes</code> 结尾。</p><p>MissFisher 中已有少部分鱼眼类型预设，可在符合天气条件时启动。</p><h2 id="出海垂钓中的稀有鱼类" tabindex="-1">出海垂钓中的稀有鱼类 <a class="header-anchor" href="#出海垂钓中的稀有鱼类" aria-label="Permalink to &quot;出海垂钓中的稀有鱼类&quot;">​</a></h2><p>在此指非幻海流钓场的绿色稀有度鱼类（普海绿鱼），如果你想钓蓝色稀有度的鱼类，请看<a href="./ocean">出海垂钓</a>。</p><p>流程与<a href="#通用方法">通用方法</a>类似，但必须在合适的时机、海域手动启动对应预设。</p>',23)])])}const u=e(l,[["render",o]]);export{f as __pageData,u as default};
